var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"이름 맥스웰. 키는 172에 검붉은 머리와 호리호리한 체형이 특징이라….","JPN":"名前、マックスウェル。身長は172に赤黒い髪とスレンダーな体型が特徴、か……","ENG":"A slim man, 172 cm tall with dark red hair named Maxwell...","TWN":"姓名，麥斯威爾，身高172，特色是紅色頭髮和身材纖細…"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"제길. 그것 참 단단히도 꼬였군.","JPN":"くそ。面倒なことになったな。","ENG":"Dammit. This isn't gonna be easy.","TWN":"該死，人這麼多是要怎麼找。"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"멍청이가 아니고서야 그대로 다닐 리는 없을 테고, 목소리 정도로 알아챌 수밖에 없나?","JPN":"そのまま歩き回るバカでもないだろうし、声で察するしかないか？","ENG":"He won't be walking around with that appearance unless he's a fool. So, I need to find him just by his voice?","TWN":"他又不是笨蛋，肯定不會用平常的樣子出現吧？難道只能靠認聲音嗎？"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"다른 녀석들은…….","JPN":"他のやつらは……","ENG":"The others were–","TWN":"其他人呢……"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_BUNNY_NULL_NULL","text":{"KOREA":"쫄리면 뒤지십시오, 휴먼.","JPN":"ビビったのなら飛び降りなさい、ヒューマン。","ENG":"Fold if you are feeling the heat, human.","TWN":"怕的話就蓋牌吧，人類。"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"크윽! 주, 죽겠습니다….","JPN":"くうっ！　お、降ります……","ENG":"Kgh! I-I fold...","TWN":"可惡！輸了…"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"저 여자. 굉장하잖아! 벌써 몇 연승째야?","JPN":"あの女、すごいな！　もう何連勝だ？","ENG":"She's incredible! What a win streak!","TWN":"那女的，好強！她都連續贏幾次啦？"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"칩이란 칩은 다 쓸어 담고 있어. 저런 실력자가 대체 어디서…!","JPN":"全部のチップをかき集めてる。いったいどこであんな凄腕が……！","ENG":"She's scraping up all the chips. Where did someone like her even come from...?","TWN":"她的籌碼多到檯面上都放不下咧，她到底是誰…！"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"HORIZON_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"……저 빌어먹을 고철.","JPN":"……あのくそ鉄くず。","ENG":"...That scrap metal.","TWN":"……那個該死的廢鐵。"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_BUNNY_NULL_NULL","text":{"KOREA":"꼬맹이 쪽은….","JPN":"ガキの方は……","ENG":"How's the kid doing...?","TWN":"小鬼呢…"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"RITA_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"그래서…! 있는 돈이란 돈은 다 날려버렸어!","JPN":"それで……！　ありったけのお金を無くしちゃったんだ！","ENG":"That's how...! I blew away all my money!","TWN":"所以…！我的錢全輸光了！"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"이런 사람을 대체, 대체 누가 좋아해 주겠냐고!","JPN":"いったい誰が、誰がこんな人間を愛してくれるんだよ！","ENG":"How can anyone like someone like me?!","TWN":"到底誰會喜歡我這種人！"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"괜찮아요! 누가 그랬는데, 불행이란 건 상대적인 거래요.","JPN":"大丈夫です！　どこかで聞いたんですけど、不幸ってものは相対的なものですって。","ENG":"It's all right! Someone told me that unhappiness is relative.","TWN":"沒事的！有人說過，不幸是比較出來的。"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"아저씨는 이곳에 왜 오셨나요?","JPN":"おじさんはどうしてここに？","ENG":"But why did you come here, mister?","TWN":"叔叔你怎麼會來這裡？"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"그, 그야… 게임에서 딴 돈으로 빚을 탕감하기 위해서지.","JPN":"そ、そりゃ……ゲームで稼いだお金で、借金を返すためだな。","ENG":"Th-that's... so I can win big and pay off my debts.","TWN":"因為…我想要用贏來的錢還債。"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"FOOLSDAY_GAMB_NPC_NULL","text":{"KOREA":"이런 확률 낮은 도박에 기대야 할 정도로 내 삶은 불행하다고!","JPN":"こんな確率の低い賭けに頼らないとダメなほど、俺の人生は不幸なんだ！","ENG":"My life is so unfortunate that I have to play these low-probability gambling games!","TWN":"人家說十賭九輸，我竟然還來賭，難怪我的人生會這麼悲慘！"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"하지만 확률 낮은 게임에 도전할 정도로 아저씨는 용기 있는 분이시잖아요.","JPN":"でも、確率の低いゲームに挑戦するくらいだから、おじさんは勇気のある方でしょう？","ENG":"But it shows that you're brave enough to challenge these low-probability games.","TWN":"贏的機率這麼低你還敢來賭，就表示你很有勇氣呢。"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"이깟 슬롯머신에서 잭팟을 터트리는 것보다, 까짓거 인생. 별거 아닐 거예요!","JPN":"スロットマシンでジャックポットを当てることより、人生なんて大したことないはずです！","ENG":"Life will be easier than hitting a jackpot on one of the slot machines!","TWN":"人生再怎麼難，也不會比在拉霸機中頭獎還要難，沒事的！"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"그러니까……","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DASH_BUNNY_NULL_NULL","text":{"KOREA":"눈물 요정아, 달아나라! 뚝!","JPN":"涙の妖精よ、飛んでけ！","ENG":"Go away, tear fairy! Shoo!","TWN":"眼淚仙子，快快走。"},"stage":{"bg":"HAVEN","slots":{"L":null,"C":{"char_id":"DASH_BUNNY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};